contracts/BotBridge.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.22;

import "./interface/IERC20BurnMint.sol";
import {IBridge} from "./interface/IBridge.sol";
import "@openzeppelin/contracts/utils/Address.sol";
import {IBotGasOracle} from "./interface/IBotGasOracle.sol";
import {IBotBridge} from "./interface/IBotBridge.sol";
import {IVote} from "./interface/IVote.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/utils/Strings.sol";
import {AccessControl} from "@openzeppelin/contracts/access/AccessControl.sol";
import {Initializable} from "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";

contract BotBridge is AccessControl, IBotBridge, Initializable {
    using Address for address;
    using SafeERC20 for IERC20;

    error ErrAssetsType(uint8 assetsType);

    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");
    bytes32 public constant BRIDGE_ROLE = keccak256("BRIDGE_ROLE");
    bytes32 public constant FINANCE_ROLE = keccak256("FINANCE_ROLE");
    bytes32 public constant RELAYER_ROLE = keccak256("RELAYER_ROLE");
    uint8 public constant CROSS_CHAIN_EXT_BOT_GAS = 1;

    IBridge public Bridge; // bridge 合约
    uint256 public localNonce; // 跨链nonce
    address private feeAddress;
    address public serverAddress;
    uint256 private withdrawNonce; // 提款nonce
    mapping(uint256 => Withdrawal) private withdrawals;
    address private superAdminAddress;
    mapping(address => bool) public blacklist; // 用户地址 => 是否在黑名单
    mapping(uint256 => DepositRecord) public depositRecords; // user => (depositNonce=> Deposit Record)
    /// @notice public mapping 自动生成 getter `refundDatas(uint256)`，返回字段顺序见 IBotBridge.RefundData，与 relayernode refundDatasABI 一致
    mapping(uint256 => RefundData) public refundDatas; // nonce=>RefundData
    /// @dev BCR-03: 源链记录「目标链已执行」，供 adminRefund 与 markExecutionConfirmed 互斥
    mapping(uint256 => bool) public executionConfirmed;
    /// @notice 本链 Vote；非零时 execute 复核 Vote.sourceRefunded（与 RELAYER markSourceRefunded 对齐）
    address public voteRef;
    BotGasConfig private botGasConfig;
    bool private botGasEnabled;


    event Refunded(uint256 indexed localNonce, address indexed sender, uint256 amount, uint256 fee, uint256 originAmount);
    event ExecutionConfirmed(uint256 indexed localNonce, address indexed confirmer);
    /// @dev BCR-17: 关键环境地址变更事件
    event EnvUpdated(address indexed feeAddress, address indexed serverAddress, address indexed bridgeAddress);
    /// @dev BCR-03/BCR-17: 记录用于执行前复核 sourceRefunded 的 Vote 地址
    event VoteRefUpdated(address indexed voteRef);
    /// @dev BCR-17: BOT Gas 配置变更（含决定资金拆分的 oracle 地址），供链下监控/事后审计
    event BotGasConfigUpdated(
        uint256 destinationChainId,
        bytes32 resourceId,
        uint256 amount,
        address oracle,
        address baseToken,
        address quoteToken,
        uint32 twapWindow,
        bool enabled
    );
    error MissingRefundOperatorRole();

    /// @custom:oz-upgrades-unsafe-allow constructor
    /// @dev BCR-10: 防止实现合约被外部初始化
    constructor() {
        _disableInitializers();
    }

    function initialize() public initializer {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
    }

    /**
        @notice 设置
        @param bridgeAddress_ bridge合约地址
        @param serverAddress_ 服务端价格签名地址
        @param feeAddress_ 跨链费接受地址
     */
    function adminSetEnv(
        address feeAddress_,
        address serverAddress_,
        address bridgeAddress_
    ) external onlyRole(ADMIN_ROLE) {
        require(feeAddress_ != address(0), "feeAddress_ error");
        // BCR-14: 补齐关键地址非零校验
        require(serverAddress_ != address(0), "serverAddress_ error");
        require(bridgeAddress_ != address(0), "bridgeAddress_ error");
        feeAddress = feeAddress_;
        serverAddress = serverAddress_;
        Bridge = IBridge(bridgeAddress_);
        emit EnvUpdated(feeAddress_, serverAddress_, bridgeAddress_);
    }

    /// @notice 绑定本链 Vote；部署后应设为当前链 Vote 代理地址以启用 execute 侧 BCR-03 校验
    function adminSetVoteRef(address vote_) external onlyRole(ADMIN_ROLE) {
        voteRef = vote_;
        emit VoteRefUpdated(vote_);
    }

    /**
        @notice 添加用户黑名单
        @param user 用户地址
     */
    function adminAddBlacklist(address user) external onlyRole(ADMIN_ROLE) {
        blacklist[user] = true;
        emit AddBlacklist(user);
    }

    /**
        @notice 移除用户黑名单
        @param user 用户地址
     */
    function adminRemoveBlacklist(address user) external onlyRole(ADMIN_ROLE) {
        blacklist[user] = false;
        emit RemoveBlacklist(user);
    }

    /**
        @notice 发起跨链
        @param destinationChainId 目标链ID
        @param resourceId 跨链桥设置的resourceId
        @param recipient 目标链资产接受者地址
        @param amount 跨链金额
     */
    function deposit(
        uint256 destinationChainId,
        bytes32 resourceId,
        address recipient,
        uint256 amount
    ) external payable {
        _deposit(destinationChainId, resourceId, recipient, amount, 0, 0);
    }

    function depositWithBotGas(
        uint256 destinationChainId,
        bytes32 resourceId,
        address recipient,
        uint256 amount
    ) external payable {
        uint256 botGasAmountSnapshot = botGasConfig.amount;
        _deposit(
            destinationChainId,
            resourceId,
            recipient,
            amount,
            CROSS_CHAIN_EXT_BOT_GAS,
            botGasAmountSnapshot
        );
    }

    function adminSetBotGasConfig(
        BotGasConfig calldata cfg,
        bool enabled
    ) external onlyRole(ADMIN_ROLE) {
        require(
            cfg.destinationChainId != 0 && cfg.resourceId != bytes32(0) && cfg.amount != 0,
            "invalid bot gas config"
        );
        // 仅当本实例是「BOT Gas 目标链」时，execute 才会询价拆主币，故此时强制询价字段齐备；
        // 源链实例不强制（oracle/baseToken/quoteToken/twapWindow 在源链不被使用）。
        if (block.chainid == cfg.destinationChainId) {
            require(cfg.oracle != address(0), "oracle required on dest");
            require(cfg.baseToken != address(0) && cfg.quoteToken != address(0), "tokens required on dest");
            require(cfg.twapWindow > 0, "twap window required on dest");
        }
        botGasConfig = cfg;
        botGasEnabled = enabled;
        emit BotGasConfigUpdated(
            cfg.destinationChainId,
            cfg.resourceId,
            cfg.amount,
            cfg.oracle,
            cfg.baseToken,
            cfg.quoteToken,
            cfg.twapWindow,
            enabled
        );
    }

    function getBotGasConfig()
        external
        view
        returns (BotGasConfig memory cfg, bool enabled)
    {
        return (botGasConfig, botGasEnabled);
    }

    function _deposit(
        uint256 destinationChainId,
        bytes32 resourceId,
        address recipient,
        uint256 amount,
        uint8 crossChainExtType,
        uint256 botGasAmountSnapshot
    ) internal {
        DepositData memory depositData;
        depositData.amount = amount;
        depositData.recipient = recipient;
        depositData.resourceId = resourceId;
        depositData.destinationChainId = destinationChainId;
        depositData.chainId = block.chainid;
        // 检查黑名单
        require(
            !blacklist[msg.sender] && !blacklist[recipient],
            "you or recipient is blocked"
        );
        // 检测resource ID是否设置
        (
        uint8 assetsType,
        address tokenAddress, // bool pause,
        bool pause,
        uint256 decimal,
        bool burnable, // bool mintable

        ) = Bridge.getTokenInfoByResourceId(depositData.resourceId);
        require(!pause, "token id paused");
        // decimal 为 Token 小数位对应的 scale 因子（如 1e6、1e18），非指数，不做 10**dec 转换
        require(decimal > 0, "invalid decimal scale");
        _requireDepositAmountUsdBounds(amount, decimal);
        depositData.fee = Bridge.chainAndTokenFee(depositData.destinationChainId, depositData.resourceId);
        //        require(depositData.fee >= 0, "fee error");
        depositData.burnable = burnable;
        depositData.assetsType = assetsType;
        depositData.tokenAddress = tokenAddress;
        require(depositData.assetsType > 0, "resourceId not exist");
        // 检测目标链ID
        require(
            depositData.destinationChainId != depositData.chainId,
            "destinationChainId error"
        );
        // BCR-08: BotBridge 侧按 sourceChainId -> destinationChainId 提前拦截未启用路线
        require(Bridge.isSupportedRoute(depositData.chainId, depositData.destinationChainId), "route not supported");
        if (crossChainExtType == CROSS_CHAIN_EXT_BOT_GAS) {
            _requireBotGasDeposit(
                destinationChainId,
                resourceId,
                botGasAmountSnapshot
            );
        }
        // BCR-11: fee 未配置时 mapping 默认 0，必须禁止免费绕过 ,手续费就是要=0，这个是需求
       // require(depositData.fee > 0, "fee not configured");
        // 实际到账额度
        (uint256 finalFeeAmount, uint256 receiveAmount) = _computeFeeAmounts(
            depositData.amount,
            depositData.fee,
            decimal
        );
        depositData.feeAmount = finalFeeAmount;
        depositData.receiveAmount = receiveAmount;

        _collectDepositFunds(
            assetsType,
            tokenAddress,
            burnable,
            depositData.amount,
            receiveAmount,
            finalFeeAmount
        );

        _recordAndBridgeDeposit(
            depositData,
            assetsType,
            tokenAddress,
            decimal,
            crossChainExtType,
            botGasAmountSnapshot
        );
    }

    function _requireBotGasDeposit(
        uint256 destinationChainId,
        bytes32 resourceId,
        uint256 botGasAmountSnapshot
    ) private view {
        require(botGasEnabled, "bot gas disabled");
        require(
            destinationChainId == botGasConfig.destinationChainId &&
                resourceId == botGasConfig.resourceId &&
                botGasAmountSnapshot > 0,
            "invalid bot gas deposit"
        );
    }

    function _computeFeeAmounts(
        uint256 amount,
        uint256 feeBps,
        uint256 scale
    ) internal view returns (uint256 finalFeeAmount, uint256 receiveAmount) {
        uint256 feeAmount = (amount * feeBps) / 10000;
        if (feeAmount > 0) {
            uint256 minRequired = Bridge.minFee() * scale;
            finalFeeAmount = feeAmount > minRequired ? feeAmount : minRequired;
        }
        require(amount > finalFeeAmount, "amount is too small");
        receiveAmount = amount - finalFeeAmount;
    }

    function _collectDepositFunds(
        uint8 assetsType,
        address tokenAddress,
        bool burnable,
        uint256 amount,
        uint256 receiveAmount,
        uint256 finalFeeAmount
    ) internal {
        if (assetsType == uint8(AssetsType.Coin)) {
            require(msg.value == amount, "incorrect value supplied .");
            Address.sendValue(payable(feeAddress), finalFeeAmount);
            return;
        }
        if (assetsType == uint8(AssetsType.Erc20)) {
            IERC20 erc20 = IERC20(tokenAddress);
            if (burnable) {
                IERC20BurnMint(tokenAddress).burnFrom(msg.sender, receiveAmount);
            } else {
                erc20.safeTransferFrom(msg.sender, address(this), receiveAmount);
            }
            erc20.safeTransferFrom(msg.sender, feeAddress, finalFeeAmount);
            return;
        }
        revert ErrAssetsType(assetsType);
    }

    function _recordAndBridgeDeposit(
        DepositData memory depositData,
        uint8 assetsType,
        address tokenAddress,
        uint256 decimal,
        uint8 crossChainExtType,
        uint256 botGasAmountSnapshot
    ) internal {
        localNonce++;

        depositRecords[localNonce] = DepositRecord(
            tokenAddress,
            msg.sender,
            depositData.recipient,
            depositData.amount,
            depositData.feeAmount,
            depositData.destinationChainId
        );

        refundDatas[localNonce] = RefundData(
            msg.sender,
            depositData.receiveAmount,
            !depositData.burnable,
            false,
            assetsType,
            tokenAddress,
            depositData.fee,
            depositData.amount
        );

        bytes memory data;
        if (crossChainExtType == CROSS_CHAIN_EXT_BOT_GAS) {
            data = abi.encode(
                depositData.resourceId,
                depositData.chainId,
                msg.sender,
                depositData.recipient,
                depositData.amount,
                depositData.receiveAmount,
                decimal,
                localNonce,
                crossChainExtType,
                botGasAmountSnapshot
            );
        } else {
            data = abi.encode(
                depositData.resourceId,
                depositData.chainId,
                msg.sender,
                depositData.recipient,
                depositData.amount,
                depositData.receiveAmount,
                decimal,
                localNonce
            );
        }

        Bridge.deposit(depositData.destinationChainId, depositData.resourceId, data);

        emit DepositEvent(
            msg.sender,
            depositData.recipient,
            depositData.amount,
            depositData.receiveAmount,
            tokenAddress,
            localNonce,
            depositData.destinationChainId
        );
    }

    function _requireVoteSourceNotRefundedByHash(
        uint256 originChainId,
        uint256 originNonce,
        bytes32 dataHash
    ) private view {
        address v = voteRef;
        if (v == address(0)) {
            return;
        }
        require(originNonce < (1 << 224), "origin nonce too big");
        uint256 nonceAndID = (originNonce << 32) |
            (originChainId & 0xFFFFFFFF);
        require(!IVote(v).sourceRefunded(nonceAndID, dataHash), "source already refunded");
    }

    /**
        @notice 目标链执行到帐操作（唯一入口）。普通跨链 crossChainExtType=0；
                到账附带 BOT Gas crossChainExtType=1。由 Vote.executeProposal 调用。
     */
    function execute(
        bytes32 resourceId,
        uint256 originChainId,
        address caller,
        address recipient,
        uint256 amount,
        uint256 receiveAmount,
        uint256 decimalOrigin,
        uint256 originNonce,
        bytes32 dataHash,
        uint8 crossChainExtType,
        uint256 botGasAmountSnapshot
    ) external onlyRole(BRIDGE_ROLE) {
        _requireVoteSourceNotRefundedByHash(originChainId, originNonce, dataHash);
        require(crossChainExtType == 0 || crossChainExtType == CROSS_CHAIN_EXT_BOT_GAS, "invalid ext type");

        ExecuteData memory executeData;
        executeData.resourceId = resourceId;
        executeData.originChainId = originChainId;
        executeData.caller = caller;
        executeData.recipient = recipient;
        executeData.amount = amount;
        executeData.receiveAmount = receiveAmount;
        executeData.decimalOrigin = decimalOrigin;
        executeData.originNonce = originNonce;

        (
            uint8 assetsType,
            address tokenAddress, // bool pause
            ,
            uint256 decimalLocal, // uint256 fee // bool burnable
            ,
            bool mintable // mintable
        ) = Bridge.getTokenInfoByResourceId(executeData.resourceId);
        // 源/目的 Token 的 scale 因子（如 1e6、1e18）
        require(executeData.decimalOrigin > 0 && decimalLocal > 0, "invalid decimal scale");
        if (executeData.decimalOrigin > decimalLocal) {
            executeData.receiveAmount =
                executeData.receiveAmount /
                (executeData.decimalOrigin / decimalLocal);
        } else if (executeData.decimalOrigin < decimalLocal) {
            executeData.receiveAmount =
                executeData.receiveAmount *
                (decimalLocal / executeData.decimalOrigin);
        }

        if (crossChainExtType == CROSS_CHAIN_EXT_BOT_GAS) {
            // 仅当「本链 == 配置的 BOT Gas 目标链(BOT Chain)」时才拆主币；
            // 否则（如目标链是 BSC/ETH 等非 botchain）即使带了 botGasAmount 也不兑换主币，
            // 默认回退到普通到账（只发 USDT），不 revert。
            if (block.chainid == botGasConfig.destinationChainId) {
                _executeWithBotGas(executeData, assetsType, tokenAddress, mintable, dataHash, botGasAmountSnapshot);
            } else {
                _executeNormal(executeData, assetsType, tokenAddress, mintable, dataHash);
            }
        } else {
            require(botGasAmountSnapshot == 0, "unexpected bot gas amount");
            _executeNormal(executeData, assetsType, tokenAddress, mintable, dataHash);
        }
    }

    function _executeNormal(
        ExecuteData memory executeData,
        uint8 assetsType,
        address tokenAddress,
        bool mintable,
        bytes32 dataHash
    ) private {
        if (assetsType == 1) {
            Address.sendValue(
                payable(executeData.recipient),
                executeData.receiveAmount
            );
        } else if (assetsType == 2) {
            if (mintable) {
                IERC20BurnMint erc20 = IERC20BurnMint(tokenAddress);
                erc20.mint(executeData.recipient, executeData.receiveAmount);
            } else {
                IERC20 erc20 = IERC20(tokenAddress);
                erc20.safeTransfer(
                    executeData.recipient,
                    executeData.receiveAmount
                );
            }
        } else {
            revert ErrAssetsType(assetsType);
        }
        emit ExecuteEvent(
            executeData.caller,
            executeData.recipient,
            executeData.receiveAmount,
            tokenAddress,
            executeData.originNonce,
            executeData.originChainId,
            dataHash,
            0,
            0,
            0
        );
    }

    function _executeWithBotGas(
        ExecuteData memory executeData,
        uint8 assetsType,
        address tokenAddress,
        bool mintable,
        bytes32 dataHash,
        uint256 botGasAmountSnapshot
    ) private {
        require(botGasEnabled, "bot gas disabled");
        require(executeData.resourceId == botGasConfig.resourceId, "only bot gas resource");
        require(assetsType == uint8(AssetsType.Erc20), "only erc20 bot gas");
        require(botGasAmountSnapshot > 0, "invalid bot gas amount");
        require(address(this).balance >= botGasAmountSnapshot, "insufficient bot gas reserve");

        // 真实 TWAP 询价：把 botGasAmountSnapshot 数量的 BOT 折算成 USDT 成本。
        // 任何询价异常（池子无流动性 / 观察窗口不足 / 未配置）都会 revert，使整笔 execute 回滚（可重试/退款）。
        BotGasConfig memory cfg = botGasConfig;
        require(cfg.oracle != address(0), "bot gas oracle not set");
        require(cfg.baseToken != address(0) && cfg.quoteToken != address(0), "bot gas token not set");
        require(cfg.twapWindow > 0, "invalid twap window");
        require(botGasAmountSnapshot <= type(uint128).max, "bot gas amount overflow");
        uint256 botCostUsdt = IBotGasOracle(cfg.oracle).quoteWithWindow(
            cfg.baseToken,
            cfg.quoteToken,
            uint128(botGasAmountSnapshot),
            cfg.twapWindow
        );
        require(botCostUsdt > 0, "invalid bot gas cost");
        require(executeData.receiveAmount > botCostUsdt, "receive amount too small");
        uint256 usdtAmount = executeData.receiveAmount - botCostUsdt;

        if (mintable) {
            IERC20BurnMint(tokenAddress).mint(executeData.recipient, usdtAmount);
        } else {
            IERC20(tokenAddress).safeTransfer(executeData.recipient, usdtAmount);
        }
        Address.sendValue(payable(executeData.recipient), botGasAmountSnapshot);

        emit ExecuteEvent(
            executeData.caller,
            executeData.recipient,
            usdtAmount,
            tokenAddress,
            executeData.originNonce,
            executeData.originChainId,
            dataHash,
            CROSS_CHAIN_EXT_BOT_GAS,
            botGasAmountSnapshot,
            botCostUsdt
        );
    }

    /// @notice BCR-03: 由 relayer 在源链调用，在目标链 execute 成功后回写，阻止源链 adminRefund
    function markExecutionConfirmed(uint256 refundNonce) external onlyRole(RELAYER_ROLE) {
        require(refundDatas[refundNonce].sender != address(0), "invalid record");
        executionConfirmed[refundNonce] = true;
        emit ExecutionConfirmed(refundNonce, msg.sender);
    }

    /**
        @notice 提取跨链桥资产，创建
        @param _tokenAddress 币种地址，coin为0地址
        @param _to 资产接受地址
        @param _amount 提取数量
     */
    function withdrawalCreate(
        address _tokenAddress,
        address payable _to,
        uint256 _amount
    ) public onlyRole(FINANCE_ROLE) returns (uint256 id) {
        id = ++withdrawNonce;
        Withdrawal storage w = withdrawals[id];
        w.withdrawalNonce = id;
        w.tokenAddress = _tokenAddress;
        w.to = _to;
        w.amount = _amount;
        w.executed = false;
        w.approved[msg.sender] = true;
        w.approvals = 1;

        emit CreatedWithdrawal(id, msg.sender, _tokenAddress, _to, _amount);
        emit ApprovedWithdrawal(w.withdrawalNonce, msg.sender);
    }

    /**
        @notice 提取跨链桥资产,授权，授权到一定数量(>=2)就通过
     */
    function withdrawalApprove(
        uint256 withdrawalId
    ) public onlyRole(FINANCE_ROLE) {
        Withdrawal storage w = withdrawals[withdrawalId];
        require(withdrawalId <= withdrawNonce, "invalid withdrawalId");
        require(!w.executed, "already executed");
        require(!w.approved[msg.sender], "already approved");
        w.approved[msg.sender] = true;
        w.approvals += 1;
        if (w.approvals >= 2) {
            w.executed = true;
            if (w.tokenAddress == address(0)) {
                Address.sendValue(w.to, w.amount);
            } else {
                IERC20 erc20 = IERC20(w.tokenAddress);
                erc20.safeTransfer(w.to, w.amount);
            }
            emit ExecutedWithdrawal(w.withdrawalNonce, msg.sender);
        }
        emit ApprovedWithdrawal(w.withdrawalNonce, msg.sender);
    }

    receive() external payable {
        emit ReceivedEth(msg.sender, msg.value);
    }


    /// @notice
    function adminRefund(uint256 refundNonce) external {
        if (
             !hasRole(RELAYER_ROLE, msg.sender) &&
             !hasRole(ADMIN_ROLE, msg.sender)
        ) {
            revert MissingRefundOperatorRole();
        }
        RefundData memory refundData = refundDatas[refundNonce];
        require(!refundData.refunded, "already refunded");
        // BCR-03: 已确认目标链执行成功的单据禁止再退款，防止双重兑付
        require(!executionConfirmed[refundNonce], "already executed on destination");
        uint256 amount = refundData.depositReceiveAmount;
        require(amount > 0, "zero amount");
        require(refundData.sender != address(0), "invalid record");
        refundDatas[refundNonce].refunded = true;
        if (refundData.assetsType == uint8(AssetsType.Coin)) {
            Address.sendValue(payable(refundData.sender), amount);
        } else {
            // BCR-05: lock 模式 transfer；burn 模式 mint，避免挪用合约库存退款
            if (refundData.depositIsLock) {
                IERC20(refundData.tokenAddress).safeTransfer(refundData.sender, amount);
            } else {
                IERC20BurnMint(refundData.tokenAddress).mint(refundData.sender, amount);
            }
        }
        emit Refunded(refundNonce, refundData.sender, amount, refundData.fee, refundData.originAmount);
    }

    /**
     * @notice 查询指定 resourceId 对应 token 是否已暂停跨链（供前端展示）
     * @param resourceId 跨链资源 ID
     * @return 是否暂停：true=已暂停，false=未暂停
     */
    /**升级修改*/
    function getTokenPauseByResourceId(bytes32 resourceId) public view returns (bool) {
        (, , bool pause, , ,) = Bridge.getTokenInfoByResourceId(resourceId);
        return pause;
    }

    /**
     * @notice 查询全桥是否暂停（供前端展示）
     * @return 是否暂停：true=已暂停，false=未暂停
     */
    /**升级修改*/
    function getBridgePause() public view returns (bool) {
        return Bridge.getPause();
    }

    /**
     * @notice Bridge 全局单笔跨链最小 USD 参照值（与 deposit 中 min 校验同源）
     * @return 与 IBridge.minAmountUsd() 相同
     */
    function getMinAmountUsd() public view returns (uint256) {
        return Bridge.minAmountUsd();
    }

    /**
     * @notice Bridge 全局单笔跨链最大 USD 参照值（与 deposit 中 max 校验同源）
     * @return 与 IBridge.maxAmountUsd() 相同
     */
    function getMaxAmountUsd() public view returns (uint256) {
        return Bridge.maxAmountUsd();
    }

    function getMinFee() public view returns (uint256) {
        return Bridge.minFee();
    }

    /// @dev 单独函数避免 deposit 栈过深（string.concat + 多局部变量）
    function _requireDepositAmountUsdBounds(uint256 amount, uint256 scale) private view {
        uint256 minUsd = Bridge.minAmountUsd();
        uint256 maxUsd = Bridge.maxAmountUsd();
        uint256 minScaled = minUsd * scale;
        uint256 maxScaled = maxUsd * scale;
        require(
            amount >= minScaled,
            string.concat(
                "The value of cross-chain assets must be greater than $",
                Strings.toString(minUsd),
                "!"
            )
        );
        if(block.chainid == 677 || block.chainid == 968) {
            require(
                amount <= maxScaled,
                string.concat(
                    "The value of cross-chain assets must be less than $",
                    Strings.toString(maxUsd),
                    "!"
                )
            );
        }
    }
}

contracts/Bridge.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.22;

import "./utils/Pausable.sol";
import {IBridge} from "./interface/IBridge.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";
import {AccessControl} from "@openzeppelin/contracts/access/AccessControl.sol";

contract Bridge is IBridge, Pausable, AccessControl, Initializable {
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");
    bytes32 public constant BRIDGE_ROLE = keccak256("BRIDGE_ROLE");

    mapping(uint256 => uint256) public fee;  /* deprecated */ // destinationChainId => fee 该币的跨链费用,折合U的数量
    mapping(uint256 => uint256) public depositCounts; // destinationChainID => number of deposits
    mapping(bytes32 => TokenInfo) public resourceIdToTokenInfo; //  resourceID => 设置的Token信息
    mapping(uint256 => mapping(uint256 => DepositRecord)) public depositRecords; // depositNonce => (destinationChainId => Deposit Record)
    /**升级修改*/
    mapping(uint256 => mapping(bytes32 => uint256)) public chainAndTokenFee;
    uint256 public minFee;
    uint256 public minAmountUsd;
    uint256 public maxAmountUsd;
    /// @dev BCR-08: sourceChainId => destinationChainId list，供前端/后端按源链查询目标链，并作为唯一路线存储
    mapping(uint256 => uint256[]) private supportedDestinationChains;

    event TradeFeeUpdated(uint256 minFee, uint256 minAmountUsd, uint256 maxAmountUsd);
    event ChainTokenFeeUpdated(uint256 destinationChainId, bytes32 indexed resourceId, uint256 fee);

    /// @custom:oz-upgrades-unsafe-allow constructor
    /// @dev BCR-10: 防止实现合约被外部初始化
    constructor() {
        _disableInitializers();
    }

    function initialize() public initializer {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
    }

    // 获取跨链费用
    function adminSetFee(
        uint256[] calldata destinationChainId_,
        uint256[] calldata fee_
    ) public view onlyRole(ADMIN_ROLE) {
        destinationChainId_;
        fee_;
        // BCR-12: 废弃旧 fee 映射入口，防止运维误以为已生效
        revert("deprecated: use adminSetChainAndTokenFee");
    }
    /**升级修改*/
    function adminSetChainAndTokenFee(ChainTokenFee[] calldata fees) public onlyRole(ADMIN_ROLE) {
        require(fees.length > 0, "array is null");
        uint256 len = fees.length;
        for (uint256 i = 0; i < len; i++) {
            ChainTokenFee memory chainTokenFee = fees[i];
            chainAndTokenFee[chainTokenFee.destinationChainId][chainTokenFee.resourceId] = chainTokenFee.fee;
            emit ChainTokenFeeUpdated(chainTokenFee.destinationChainId, chainTokenFee.resourceId, chainTokenFee.fee);
        }
    }

    /// @dev BCR-08/BCR-17: 设置 sourceChainId 对应的完整目标链列表，并记录事件
    function adminSetSupportedRoutes(
        uint256 sourceChainId,
        uint256[] calldata destinationChainIds
    ) public onlyRole(ADMIN_ROLE) {
        require(sourceChainId > 0, "sourceChainId error");
        delete supportedDestinationChains[sourceChainId];
        uint256 len = destinationChainIds.length;
        for (uint256 i = 0; i < len; i++) {
            uint256 destinationChainId = destinationChainIds[i];
            require(destinationChainId > 0, "destinationChainId error");
            require(destinationChainId != sourceChainId, "destinationChainId error");
            require(!_isSupportedRoute(sourceChainId, destinationChainId), "duplicate destinationChainId");
            supportedDestinationChains[sourceChainId].push(destinationChainId);
        }
        emit SupportedRoutesUpdated(sourceChainId, destinationChainIds);
    }

    /// @dev BCR-08: 从 sourceChainId 的目标链列表中查询 destinationChainId 是否已启用
    function isSupportedRoute(uint256 sourceChainId, uint256 destinationChainId) external view returns (bool) {
        return _isSupportedRoute(sourceChainId, destinationChainId);
    }

    /// @dev BCR-08: 返回某条源链已启用的全部目标链
    function getSupportedDestinationChains(uint256 sourceChainId) external view returns (uint256[] memory) {
        return supportedDestinationChains[sourceChainId];
    }

    function _isSupportedRoute(uint256 sourceChainId, uint256 destinationChainId) private view returns (bool) {
        uint256[] storage destinations = supportedDestinationChains[sourceChainId];
        uint256 len = destinations.length;
        for (uint256 i = 0; i < len; i++) {
            if (destinations[i] == destinationChainId) {
                return true;
            }
        }
        return false;
    }

    /**升级修改*/
    function adminSetTradeFee(uint256 _minFee, uint256 _minAmountUsd, uint256 _maxAmountUsd) public onlyRole(ADMIN_ROLE) {
        // BCR-15: 防止配置互相矛盾导致
        require(_maxAmountUsd > 0, "maxAmountUsd is zero");
        require(_minAmountUsd < _maxAmountUsd, "invalid amount bounds");
        require(_minFee <= 10_000, "minFee too high");
        minFee = _minFee;
        minAmountUsd = _minAmountUsd;
        maxAmountUsd = _maxAmountUsd;
        emit TradeFeeUpdated(_minFee, _minAmountUsd, _maxAmountUsd);
    }

    /**
        @notice 暂停跨链、提案的的创建与投票和目标链执行操作
     */
    function adminPauseTransfers() external onlyRole(ADMIN_ROLE) {
        _pause();
    }

    /**
        @notice 开启跨链、提案的的创建与投票和目标链执行操作
     */
    function adminUnpauseTransfers() external onlyRole(ADMIN_ROLE) {
        _unpause();
    }

    /**
        @notice resource设置
        @param resourceID 跨链的resourceID
        @param assetsType 该币的类型
        @param tokenAddress 对应的token合约地址，coin为0地址
        @param decimal 该币数量级缩放因子（如 1e6、1e18），与 minAmountUsd*decimal 同量纲
        @param pause 该币种是否在黑名单中/是否允许跨链。币种黑名单/禁止该币种跨链
        @param burnable 该币是否burn
        @param mintable 该币是否mint
     */
    function adminSetResource(
        bytes32 resourceID,
        AssetsType assetsType,
        address tokenAddress,
        uint256 decimal,
        bool pause,
        bool burnable,
        bool mintable
    ) external onlyRole(ADMIN_ROLE) {
        require(uint8(assetsType) > 0, "invalid asset type");
        // decimal 存 scale（如 10**6），非指数位；仅要求非零且避免明显异常极大值造成溢出观感
        require(decimal > 0 && decimal <= 10 ** 40, "invalid decimal scale");
        // BCR-14: 资源配置时补齐资产地址语义校验
        if (assetsType == AssetsType.Coin) {
            require(tokenAddress == address(0), "coin tokenAddress must be zero");
        } else {
            require(tokenAddress != address(0), "tokenAddress is zero");
        }
        resourceIdToTokenInfo[resourceID] = TokenInfo(
            assetsType,
            tokenAddress,
            pause,
            decimal,
            burnable,
            mintable
        );

        emit SetResource(
            resourceID,
            tokenAddress,
            decimal,
            pause,
            burnable,
            mintable
        );
    }

    /**
        @notice 资产跨链
        @param destinationChainId 目标链ID
        @param resourceId 跨链的resourceID
        @param data   跨链data
     */
    function deposit(
        uint256 destinationChainId,
        bytes32 resourceId,
        bytes calldata data
    ) external whenNotPaused onlyRole(BRIDGE_ROLE) {
        // 检测resource ID是否设置
        TokenInfo memory tokenInfo = resourceIdToTokenInfo[resourceId];
        require(uint8(tokenInfo.assetsType) > 0, "resourceId not exist");
        // BCR-08: 防止用户把资产锁定/销毁到未部署或未支持的目标链路线
        require(_isSupportedRoute(block.chainid, destinationChainId), "route not supported");
        // 检测resourceId/token是否被暂停跨链
        require(!tokenInfo.pause, "service suspended");

        uint256 depositNonce = ++depositCounts[destinationChainId];

        depositRecords[destinationChainId][depositNonce] = DepositRecord(
            destinationChainId,
            msg.sender,
            resourceId,
            block.timestamp,
            data
        );

        emit Deposit(destinationChainId, resourceId, depositNonce, data);
    }

    // 由resourceId获取token信息
    function getTokenInfoByResourceId(
        bytes32 resourceId
    ) public view returns (uint8, address, bool, uint256, bool, bool) {
        TokenInfo memory token = resourceIdToTokenInfo[resourceId];
        return (
            uint8(token.assetsType),
            token.tokenAddress,
            token.pause,
            token.decimal,
            token.burnable,
            token.mintable
        );
    }
    /**升级修改*/
    function getPause() public view returns (bool){
        return paused();
    }

}

contracts/Vote.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.22;

import "./interface/IVote.sol";
import "./interface/IBridge.sol";
import "./interface/IBotBridge.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";
import {AccessControl} from "@openzeppelin/contracts/access/AccessControl.sol";

contract Vote is IVote, AccessControl, Initializable {
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");
    bytes32 public constant RELAYER_ROLE = keccak256("RELAYER_ROLE");

    error ErrAssetsType(uint8 assetsType);

    IBridge public Bridge; // bridge 合约
    IBotBridge public BotBridge; // BotBridge 合约
    uint256 public expiry; // 开始投票后经过 expiry 的块数量后投票过期
    uint256 public totalProposal; // 提案数量
    uint256 public relayerThreshold; // 提案可以通过的最少投票数量
    address private superAdminAddress;
    mapping(uint256 => mapping(bytes32 => Proposal)) public proposals; // destinationChainID + depositNonce => dataHash => Proposal
    mapping(uint256 => mapping(bytes32 => mapping(address => bool)))
        public hasVotedOnProposal; // destinationChainID + depositNonce => dataHash => relayerAddress => bool
    /// @dev BCR-03：源链已退款（或即将退款）时置位，阻塞目标链执行
    mapping(uint256 => mapping(bytes32 => bool)) public sourceRefunded;
    /// @dev BCR-17: Vote 环境参数变更事件
    event EnvUpdated(address indexed bridgeAddress, address indexed botBridgeAddress, uint256 expiry, uint256 relayerThreshold);

    struct LegacyExecutePayload {
        bytes32 resourceId;
        uint256 originChainId;
        address caller;
        address recipient;
        uint256 amount;
        uint256 receiveAmount;
        uint256 decimalOrigin;
        uint256 originNonce;
    }

    struct ExtendedExecutePayload {
        bytes32 resourceId;
        uint256 originChainId;
        address caller;
        address recipient;
        uint256 amount;
        uint256 receiveAmount;
        uint256 decimalOrigin;
        uint256 originNonce;
        uint8 crossChainExtType;
        uint256 botGasAmountSnapshot;
    }

    /// @custom:oz-upgrades-unsafe-allow constructor
    /// @dev BCR-10: 防止实现合约被外部初始化
    constructor() {
        _disableInitializers();
    }

    function initialize() public initializer {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
    }

    /**
        @notice 设置
        @param bridgeAddress_ Bridge合约地址
        @param expiry_ 提案过期的块高差
        @param relayerThreshold_ 提案通过的投票数量
     */
    function adminSetEnv(
        address bridgeAddress_,
        address botBridgeAddress_,
        uint256 expiry_,
        uint256 relayerThreshold_
    ) external onlyRole(ADMIN_ROLE) {
        // BCR-14: 关键合约地址禁止配置为零地址
        require(bridgeAddress_ != address(0), "bridgeAddress_ error");
        require(botBridgeAddress_ != address(0), "botBridgeAddress_ error");
        expiry = expiry_;
        Bridge = IBridge(bridgeAddress_);
        BotBridge = IBotBridge(botBridgeAddress_);
        relayerThreshold = relayerThreshold_;
        emit EnvUpdated(bridgeAddress_, botBridgeAddress_, expiry_, relayerThreshold_);
    }

    /**
        @notice 设置投票可通过时的最小投票数量
        @param newThreshold 投票可通过时的最小投票数量
     */
    function adminChangeRelayerThreshold(
        uint256 newThreshold
    ) external onlyRole(ADMIN_ROLE) {
        relayerThreshold = newThreshold;
        emit RelayerThresholdChanged(newThreshold);
    }

    /**
        @notice 添加relayer账户
        @notice Only callable by an address that currently has the admin role.
        @param relayerAddress Address of relayer to be added.
        @notice Emits {RelayerAdded} event.
     */
    function adminAddRelayer(
        address relayerAddress
    ) external onlyRole(ADMIN_ROLE) {
        require(
            !hasRole(RELAYER_ROLE, relayerAddress),
            "addr already has relayer role!"
        );
        grantRole(RELAYER_ROLE, relayerAddress);
        emit RelayerAdded(relayerAddress);
    }

    /**
        @notice 删除relayer账户
        @notice Only callable by an address that currently has the admin role.
        @param relayerAddress Address of relayer to be removed.
        @notice Emits {RelayerRemoved} event.
     */
    function adminRemoveRelayer(
        address relayerAddress
    ) external onlyRole(ADMIN_ROLE) {
        require(
            hasRole(RELAYER_ROLE, relayerAddress),
            "addr doesn't have relayer role!"
        );
        revokeRole(RELAYER_ROLE, relayerAddress);
        emit RelayerRemoved(relayerAddress);
    }

    /**
        @notice relayer执行投票通过后的到帐操作
        @param originChainId 源链ID
        @param originDepositNonce 源链nonce
        @param resourceId 跨链的resourceID
        @param dataHash dataHash
     */
    function voteProposal(
        uint256 originChainId,
        uint256 originDepositNonce,
        bytes32 resourceId,
        bytes32 dataHash
    ) external onlyRole(RELAYER_ROLE) {
        // BCR-16: 紧急暂停期间禁止继续投票推进提案
        require(!Bridge.getPause(), "bridge paused");
        require(
            originDepositNonce < (1 << 224),
            "origin deposit nonce too big"
        );
        uint256 nonceAndID = (originDepositNonce << 32) |
            (originChainId & 0xFFFFFFFF); // 补0保证唯一性
        require(!sourceRefunded[nonceAndID][dataHash], "source already refunded");
        Proposal storage proposal = proposals[nonceAndID][dataHash];
        require(
            uint8(proposal.status) <= 1,
            "proposal already passed/executed/cancelled"
        );
        require(
            !hasVotedOnProposal[nonceAndID][dataHash][msg.sender],
            "relayer already voted"
        );

        if (uint8(proposal.status) == 0) {
            // 第一次对提案投票
            ++totalProposal;
            proposals[nonceAndID][dataHash] = Proposal(
                resourceId,
                dataHash,
                new address[](1),
                new address[](0),
                ProposalStatus.Active,
                block.number
            );

            proposal.yesVotes[0] = msg.sender; // 索引 0 是创建提案的relayer
            emit ProposalEvent(
                originChainId,
                originDepositNonce,
                ProposalStatus.Active,
                resourceId,
                dataHash
            );
        } else {
            // 非第一次对提案投票
            if (block.number - proposal.proposedBlock > expiry) {
                // 如果块高差达到设定阀值，就取消提案,可以设置1～2天，更短时间可以增加安全性
                proposal.status = ProposalStatus.Cancelled;
                emit ProposalEvent(
                    originChainId,
                    originDepositNonce,
                    ProposalStatus.Cancelled,
                    resourceId,
                    dataHash
                );
            } else {
                require(dataHash == proposal.dataHash, "datahash mismatch");
                proposal.yesVotes.push(msg.sender);
            }
        }
        if (proposal.status != ProposalStatus.Cancelled) {
            // 提案非过期状态
            hasVotedOnProposal[nonceAndID][dataHash][msg.sender] = true;
            emit ProposalVote(
                originChainId,
                originDepositNonce,
                proposal.status,
                resourceId
            );

            // 检测投票后的提案状态
            // 如果投票数量达到设定阀值，或者阀值设置为1，就通过提案
            if (
                relayerThreshold <= 1 ||
                proposal.yesVotes.length >= relayerThreshold
            ) {
                proposal.status = ProposalStatus.Passed;
                emit ProposalEvent(
                    originChainId,
                    originDepositNonce,
                    ProposalStatus.Passed,
                    resourceId,
                    dataHash
                );
            }
        }
    }

    /**
        @notice relayer执行投票通过后的到帐操作
        @param originChainId 源链ID
        @param originDepositNonce 源链nonce
        @param dataHash dataHash
     */
    function cancelProposal(
        uint256 originChainId,
        uint256 originDepositNonce,
        bytes32 dataHash
    ) public onlyRole(RELAYER_ROLE) {
        // BCR-16: 紧急暂停期间禁止 relayer 改变提案状态
        require(!Bridge.getPause(), "bridge paused");
        require(
            originDepositNonce < (1 << 224),
            "origin deposit nonce too big"
        );
        uint256 nonceAndID = (originDepositNonce << 32) |
            (originChainId & 0xFFFFFFFF);
        Proposal storage proposal = proposals[nonceAndID][dataHash];

        require(proposal.proposedBlock > 0, "Proposal inactive");
        // BCR-06: 只能取消过期的 Active 提案，避免 Passed/Executed 提案被永久取消
        require(
            proposal.status == ProposalStatus.Active,
            "Can only cancel active proposals"
        );
        require(
            block.number - proposal.proposedBlock > expiry,
            "Proposal not at expiry threshold"
        );

        proposal.status = ProposalStatus.Cancelled;
        emit ProposalEvent(
            originChainId,
            originDepositNonce,
            ProposalStatus.Cancelled,
            proposal.resourceId,
            proposal.dataHash
        );
    }

    /// @inheritdoc IVote
    function markSourceRefunded(
        uint256 originChainId,
        uint256 originDepositNonce,
        bytes32 dataHash
    ) external onlyRole(RELAYER_ROLE) {
        require(
            originDepositNonce < (1 << 224),
            "origin deposit nonce too big"
        );
        uint256 nonceAndID = (originDepositNonce << 32) |
            (originChainId & 0xFFFFFFFF);
        Proposal storage proposal = proposals[nonceAndID][dataHash];

        sourceRefunded[nonceAndID][dataHash] = true;
        if (proposal.proposedBlock > 0) {
            require(proposal.status != ProposalStatus.Executed, "proposal already executed");
            if (
                proposal.status == ProposalStatus.Active ||
                proposal.status == ProposalStatus.Passed
            ) {
                proposal.status = ProposalStatus.Cancelled;
                emit ProposalEvent(
                    originChainId,
                    originDepositNonce,
                    ProposalStatus.Cancelled,
                    proposal.resourceId,
                    proposal.dataHash
                );
            }
        }
        emit SourceRefundMarked(originChainId, originDepositNonce, dataHash, msg.sender);
    }

    /**
        @notice relayer执行投票通过后的到帐操作
        @param originChainId 源链ID
        @param originDepositNonce 源链nonce
        @param data 跨链data
     */
    function executeProposal(
        uint256 originChainId,
        uint256 originDepositNonce,
        bytes calldata data
    ) external onlyRole(RELAYER_ROLE) {
        // BCR-16: 紧急暂停期间禁止目标链执行放款
        require(!Bridge.getPause(), "bridge paused");
        require(
            originDepositNonce < (1 << 224),
            "origin deposit nonce too big"
        );
        uint256 nonceAndID = (originDepositNonce << 32) |
            (originChainId & 0xFFFFFFFF);
        bytes32 dataHash = keccak256(abi.encodePacked(originChainId, data));
        Proposal storage proposal = proposals[nonceAndID][dataHash];

        require(!sourceRefunded[nonceAndID][dataHash], "source already refunded");
        require(
            proposal.status == ProposalStatus.Passed,
            "the proposal must have passed"
        );
        require(
            block.number - proposal.proposedBlock <= expiry,
            "proposal execution expired"
        );
        require(dataHash == proposal.dataHash, "data doesn't match datahash");

        proposal.status = ProposalStatus.Executed;
        (
            ExecuteData memory executeData,
            uint8 crossChainExtType,
            uint256 botGasAmountSnapshot
        ) = _decodeExecuteData(data);
        BotBridge.execute(
            executeData.resourceId,
            executeData.originChainId,
            executeData.caller,
            executeData.recipient,
            executeData.amount,
            executeData.receiveAmount,
            executeData.decimalOrigin,
            executeData.originNonce,
            dataHash,
            crossChainExtType,
            botGasAmountSnapshot
        );

        emit ProposalEvent(
            originChainId,
            originDepositNonce,
            proposal.status,
            proposal.resourceId,
            proposal.dataHash
        );
    }

    function _decodeExecuteData(bytes calldata data)
        private
        pure
        returns (
            ExecuteData memory executeData,
            uint8 crossChainExtType,
            uint256 botGasAmountSnapshot
        )
    {
        if (data.length == 32 * 8) {
            LegacyExecutePayload memory payload = abi.decode(data, (LegacyExecutePayload));
            executeData = _toExecuteData(payload);
        } else if (data.length == 32 * 10) {
            ExtendedExecutePayload memory payload = abi.decode(data, (ExtendedExecutePayload));
            executeData = _toExecuteData(
                LegacyExecutePayload({
                    resourceId: payload.resourceId,
                    originChainId: payload.originChainId,
                    caller: payload.caller,
                    recipient: payload.recipient,
                    amount: payload.amount,
                    receiveAmount: payload.receiveAmount,
                    decimalOrigin: payload.decimalOrigin,
                    originNonce: payload.originNonce
                })
            );
            crossChainExtType = payload.crossChainExtType;
            botGasAmountSnapshot = payload.botGasAmountSnapshot;
        } else {
            revert("invalid deposit data length");
        }
        require(crossChainExtType == 0 || crossChainExtType == 1, "invalid ext type");
        if (crossChainExtType == 0) {
            require(botGasAmountSnapshot == 0, "unexpected bot gas amount");
        } else {
            require(botGasAmountSnapshot > 0, "empty bot gas amount");
        }
    }

    function _toExecuteData(LegacyExecutePayload memory payload)
        private
        pure
        returns (ExecuteData memory executeData)
    {
        executeData.resourceId = payload.resourceId;
        executeData.originChainId = payload.originChainId;
        executeData.caller = payload.caller;
        executeData.recipient = payload.recipient;
        executeData.amount = payload.amount;
        executeData.receiveAmount = payload.receiveAmount;
        executeData.decimalOrigin = payload.decimalOrigin;
        executeData.originNonce = payload.originNonce;
    }

    // 获取投票信息
    function getProposal(
        uint256 originChainId,
        uint256 originDepositNonce,
        bytes32 dataHash
    ) external view returns (Proposal memory) {
        require(
            originDepositNonce < (1 << 224),
            "origin deposit nonce too big"
        );
        uint256 nonceAndID = (originDepositNonce << 32) |
            (originChainId & 0xFFFFFFFF);
        return proposals[nonceAndID][dataHash];
    }
}

contracts/interface/IBotBridge.sol.content:
// SPDX-License-Identifier: UNLICENSED
pragma solidity ^0.8.22;

interface IBotBridge {
    enum AssetsType {
        None,
        Coin,
        Erc20,
        Erc721,
        Erc1155
    }

    event AddBlacklist(address indexed user);
    event RemoveBlacklist(address indexed user);
    event ReceivedEth(address sender, uint256 amount);
    event CreatedWithdrawal(
        uint256 withdrawNonce,
        address caller,
        address indexed tokenAddress,
        address indexed to,
        uint256 indexed amount
    );
    event ApprovedWithdrawal(uint256 withdrawNonce, address caller);
    event ExecutedWithdrawal(uint256 withdrawNonce, address caller);

    event DepositEvent(
        address indexed depositer,
        address indexed recipient,
        uint256 indexed amount,
        uint256 receiveAmount,
        address tokenAddress,
        uint256 depositNonce,
        uint256 destinationChainId
    );

    event SetTokenEvent(
        bytes32 indexed resourceID,
        AssetsType assetsType,
        address tokenAddress,
        bool burnable,
        bool mintable,
        bool pause // 该token是否暂停跨链
    );

    event ExecuteEvent(
        address indexed depositer,
        address indexed recipient,
        uint256 indexed receiveamount,
        address tokenAddress,
        uint256 originDepositNonce,
        uint256 originChainId,
        bytes32 dataHash,
        uint8 crossChainExtType,
        uint256 botAmount,
        uint256 botCostUsdt
    );

    struct DepositRecord {
        address tokenAddress;
        address sender;
        address recipient;
        uint256 amount;
        uint256 fee;
        uint256 destinationChainId;
    }

    struct DepositData {
        uint256 chainId;
        uint256 destinationChainId;
        bytes32 resourceId;
        address recipient;
        uint256 amount;
        uint256 value; // msg.value
        address sender; // msg.sender
        address tokenAddress;
        //        uint256 price;
        uint256 fee; // 跨链需要折合U的数量
        uint256 feeAmount;
        uint256 receiveAmount;
        bool burnable;
        uint8 assetsType;
    }

    struct ExecuteData {
        uint256 dataLength;
        bytes32 resourceId;
        uint256 originChainId;
        address caller;
        address recipient;
        uint256 amount;
        uint256 receiveAmount;
        uint256 decimalOrigin;
        uint256 originNonce;
    }

    struct Withdrawal {
        uint256 withdrawalNonce;
        address payable to;
        address tokenAddress;
        uint256 amount;
        bool executed;
        mapping(address => bool) approved;
        uint8 approvals; // number of approvals
    }

    function execute(
        bytes32 resourceId,
        uint256 originChainId,
        address caller,
        address recipient,
        uint256 amount,
        uint256 receiveAmount,
        uint256 decimalOrigin,
        uint256 originNonce,
        bytes32 dataHash,
        uint8 crossChainExtType,
        uint256 botGasAmountSnapshot
    ) external;

    function depositWithBotGas(
        uint256 destinationChainId,
        bytes32 resourceId,
        address recipient,
        uint256 amount
    ) external payable;

    /// @notice BOT Gas 配置（不含开关）；字段顺序即 storage slot 顺序，上主网后不可重排。
    /// @dev 后 4 个字段（oracle/baseToken/quoteToken/twapWindow）仅目标链 execute 询价用，源链可留空。
    struct BotGasConfig {
        uint256 destinationChainId; // 源链：目标必须是 BOT Chain（968/677）
        bytes32 resourceId;         // 源链+目标链：USDT resourceId
        uint256 amount;             // 源链：发放 BOT 数量，初始 0.1 BOT
        address oracle;             // 目标链：TWAP 报价合约（源链可为 0）
        address baseToken;          // 目标链：TWAP base = BOT 包装地址（源链可为 0）
        address quoteToken;         // 目标链：TWAP quote = USDT 地址（源链可为 0）
        uint32  twapWindow;         // 目标链：TWAP 窗口秒数，默认 1800（源链可为 0）
    }

    function adminSetBotGasConfig(
        BotGasConfig calldata cfg,
        bool enabled
    ) external;

    function getBotGasConfig() external view returns (
        BotGasConfig memory cfg,
        bool enabled
    );

    /// @dev 字段顺序与 relayernode `bridge/chains/ethereum/refund.go` 中 `refundDatasABI` 必须一致
    struct RefundData {
        address sender;
        uint256 depositReceiveAmount;
        bool depositIsLock;
        bool refunded;
        uint8 assetsType;
        address tokenAddress;
        uint256 fee;
        uint256 originAmount;
    }

    /// @notice 查询某笔 deposit（localNonce）的退款侧记录；由实现合约 `mapping(uint256 => RefundData) public refundDatas` 生成，ABI 与链下 `refundDatasABI` 一致
    function refundDatas(uint256 localNonce) external view returns (
        address sender,
        uint256 depositReceiveAmount,
        bool depositIsLock,
        bool refunded,
        uint8 assetsType,
        address tokenAddress,
        uint256 fee,
        uint256 originAmount
    );
}

contracts/interface/IBotGasOracle.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.22;

interface IBotGasOracle {
    /// @notice 按 TWAP 窗口把 baseAmount 数量的 baseToken 折算成 quoteToken 数量
    /// @dev 对接 botchain TWAP Oracle 代理（如 0x00f1BD8e…）的 quoteWithWindow(selector 0xf862b304)
    /// @param baseToken 计价基础币（BOT 的包装地址）
    /// @param quoteToken 报价币（USDT）
    /// @param baseAmount baseToken 数量（1e18 = 1 BOT）
    /// @param twapWindow TWAP 时间窗口（秒）
    /// @return quoteAmount 折算出的 quoteToken 数量（USDT 6 位精度）
    function quoteWithWindow(
        address baseToken,
        address quoteToken,
        uint128 baseAmount,
        uint32 twapWindow
    ) external view returns (uint256 quoteAmount);
}

contracts/interface/IBridge.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.22;

interface IBridge {
    enum AssetsType {
        None,
        Coin,
        Erc20,
        Erc721,
        Erc1155
    }

    event Deposit(
        uint256 indexed destinationChainId,
        bytes32 indexed resourceID,
        uint256 indexed depositNonce,
        bytes data
    );

    event SetResource(
        bytes32 indexed resourceID,
        address tokenAddress,
        uint256 decimal,
        bool pause, // 该resourceID是否被暂停交易
        bool burnable, // true burn;false lock
        bool mintable
    );

    // 跨链币种信息
    struct TokenInfo {
        AssetsType assetsType; // 跨链币种
        address tokenAddress; // 币种地址。coin的话，值为0地址
        bool pause; // 该token是否暂停跨链
        uint256 decimal; // 该token的精度
        bool burnable; // true burn;false lock
        bool mintable; // true mint;false release
    }

    struct DepositRecord {
        uint256 destinationChainId;
        address sender; // 某个业务合约的地址，可以有多个业务合约
        bytes32 resourceID;
        uint256 ctime;
        bytes data;
    }

