    function fee(uint256 destinationChainId) external view returns (uint256);

    function getTokenInfoByResourceId(
        bytes32 resourceId
    ) external view returns (uint8, address, bool, uint256, bool, bool);

    /// @return 全桥是否暂停：true=已暂停，false=未暂停
